class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        maybeRequestLegacyStorageAccess()
        LocalLibraryManager(this).ensureFolders()
        enableEdgeToEdge()
        WindowCompat.setDecorFitsSystemWindows(window, false)
        setContent {
            val xiroGreen = Color(0xFF6BD224)
            val xiroBackground = Color(0xFF2B2F39)
            val xiroSurface = Color(0xFF3A3F4A)
            val xiroNavBar = Color(0xFF252A31)
            val xiroOnNavBar = Color(0xFFE9EDF2)
            val scheme = darkColorScheme(
                primary = xiroGreen,
                secondary = xiroGreen,
                tertiary = xiroGreen,
                background = xiroBackground,
                surface = xiroSurface,
                surfaceVariant = xiroNavBar,
                onPrimary = Color.Black,
                onSecondary = Color.Black,
                onTertiary = Color.Black,
                onBackground = Color(0xFFF2F4F7),
                onSurface = Color(0xFFF2F4F7),
                onSurfaceVariant = xiroOnNavBar
            )
            MaterialTheme(colorScheme = scheme) {
                XiroLiteBetaApp()
            }
        }
    }

    private fun maybeRequestLegacyStorageAccess() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R && !Environment.isExternalStorageManager()) {
            try {
                startActivity(Intent(Settings.ACTION_MANAGE_APP_ALL_FILES_ACCESS_PERMISSION, Uri.parse("package:$packageName")))
            } catch (_: Throwable) {
                startActivity(Intent(Settings.ACTION_MANAGE_ALL_FILES_ACCESS_PERMISSION))
            }
        }
    }
}

private fun formatTimestamp(timestampMs: Long): String {
    return SimpleDateFormat("HH:mm:ss.SSS", Locale.US).format(Date(timestampMs))
}

