    var selectedProfile by remember { mutableStateOf(LegacyCompatibilityCatalog.defaultProfile) }
    val repo = remember { XiroRepository() }
    val context = LocalContext.current
    val scope = rememberCoroutineScope()

    val detector = remember { DroneNetworkDetector(context) }
    val networkInfo = detector.detect()

    val portScanner = remember { PortScanner() }
    val targetedProbe = remember { TargetedProbe() }
    val cameraInitProbe = remember { CameraInitProbe() }
    val telemetryProbe = remember { TelemetryProbe() }
    val remoteTelemetryProbe = remember { RemoteTelemetryProbe() }
    val relayProbe = remember { RelayProbe() }
    val exportHelper = remember { ExportHelper(context) }
    val liveMonitor = remember { LiveConnectionMonitor() }
    val cameraMediaController = remember(selectedProfile) { CameraMediaController(selectedProfile) }
    val captureFeedback = remember { CaptureFeedback(context) }
    val localLibraryManager = remember { LocalLibraryManager(context) }
    val hjLogRecorder = remember { HjLogRecorder(localLibraryManager) }

    var host by remember { mutableStateOf(selectedProfile.primaryHost()) }
    var selectedTab by remember { mutableStateOf(BetaTab.CAMERA) }
    var advancedVisible by remember { mutableStateOf(false) }

    var results by remember { mutableStateOf(listOf<CommandResult>()) }
    var portScanResults by remember { mutableStateOf(listOf<PortScanResult>()) }
    var targetedResults by remember { mutableStateOf(listOf<TargetedProbeResult>()) }
    var cameraInitResults by remember { mutableStateOf(listOf<CameraInitResult>()) }
    var telemetryResults by remember { mutableStateOf(listOf<TelemetryResult>()) }
    var telemetryDiffResults by remember { mutableStateOf(listOf<TelemetryDiffResult>()) }
    var relayProbeResults by remember { mutableStateOf(listOf<CommandResult>()) }
    var cameraLibrary by remember { mutableStateOf(CameraLibraryState(emptyList(), emptyList())) }
    var localLibraryItems by remember { mutableStateOf(listOf<LocalLibraryItem>()) }
    var lastCameraAction by remember { mutableStateOf<CameraOperationResult?>(null) }
    val cameraTraceLog = remember { mutableStateListOf<CameraActionResult>() }
    var captureMode by remember { mutableStateOf(CaptureMode.PHOTO) }
    var isRecording by remember { mutableStateOf(false) }

    var watch3014Result by remember { mutableStateOf<TelemetryResult?>(null) }
    var watch3014Summary by remember { mutableStateOf<Telemetry3014Summary?>(null) }

    var exportStatus by remember { mutableStateOf("") }
    var commandExportStatus by remember { mutableStateOf("") }
    var runningCommandPath by remember { mutableStateOf<String?>(null) }
    var selectedLibraryPreview by remember { mutableStateOf<LocalLibraryItem?>(null) }
    var selectedRemoteLibraryPreview by remember { mutableStateOf<CameraMediaItem?>(null) }
    var libraryViewMode by remember { mutableStateOf(LibraryViewMode.REMOTE_CAMERA) }
    var libraryRefreshing by remember { mutableStateOf(false) }
    var lastLibraryRefreshAtMs by remember { mutableLongStateOf(0L) }
    var libraryDownloadProgress by remember { mutableStateOf<LibraryDownloadProgress?>(null) }
    var showPlayer by remember { mutableStateOf(false) }
    var fullScreenPlayer by remember { mutableStateOf(false) }
    var showHud by remember { mutableStateOf(true) }
    var playerReloadToken by remember { mutableStateOf(0) }
    var captureRecoveryMessage by remember { mutableStateOf<String?>(null) }
    var lastAutoStreamReloadAtMs by remember { mutableLongStateOf(0L) }
    var autoRecoveryMessageToken by remember { mutableIntStateOf(0) }
    var telemetryRunning by remember { mutableStateOf(false) }
    var watch3014Running by remember { mutableStateOf(false) }
    var remoteUdpUserDisabled by remember { mutableStateOf(false) }
    var remoteUdpProbeInProgress by remember { mutableStateOf(false) }
    var showMonitor by remember { mutableStateOf(false) }
    var streamProfile by remember { mutableStateOf(StreamProfile.AUTO) }
    var hjLogStatusText by remember { mutableStateOf("Idle") }

    val remotePackets by LiveFlightTelemetryHub.recentPackets.collectAsState()
    val remoteUdpRunning by LiveFlightTelemetryHub.isRunning.collectAsState()
    val liveLogs = remember { mutableStateListOf<String>() }

    var monitorJob by remember { mutableStateOf<Job?>(null) }
    var telemetryJob by remember { mutableStateOf<Job?>(null) }
    var watch3014Job by remember { mutableStateOf<Job?>(null) }

    var relayBindSsid by remember { mutableStateOf("") }
    var relayBindPassword by remember { mutableStateOf("") }
    var settingsPage by remember { mutableStateOf(SettingsPage.ROOT) }
    var extenderName by remember { mutableStateOf("XPLORER_4009A8") }
    var extenderPassword by remember { mutableStateOf("Blank") }
    var selectedBindNetwork by remember { mutableStateOf<String?>(null) }
    var pendingBindNetwork by remember { mutableStateOf<RelayWifiCandidate?>(null) }
    var relayBindInProgress by remember { mutableStateOf(false) }
    val releaseNotes = remember { currentReleaseNotes() }
    val releasePrefs = remember { context.getSharedPreferences("xiro_lite_release_notes", android.content.Context.MODE_PRIVATE) }
    val uiPrefs = remember { context.getSharedPreferences("xiro_lite_ui", android.content.Context.MODE_PRIVATE) }
    var debugModeEnabled by remember { mutableStateOf(uiPrefs.getBoolean("debug_mode_enabled", false)) }
    var showDebugModeWarningDialog by remember { mutableStateOf(false) }
    var showReleaseNotesDialog by remember {
        mutableStateOf(
            releasePrefs.getString("last_ack_version", null) != releaseNotes.version
        )
    }

    val rtspUrl = selectedProfile.primaryRtspUrl(host)
    val runnableCommands = remember(selectedProfile) {
        XiroCommandCatalog.commandsFor(selectedProfile).filter { it.runnable }
    }
    val connectionStatus = remember(networkInfo) {
        when {
            networkInfo.localIp?.startsWith("192.168.2.") == true -> "Connected to XIRO extender"
            networkInfo.localIp?.startsWith("192.168.1.") == true -> "Connected to camera directly"
            else -> "Not connected to XIRO network"
        }
    }
    val relayHost = remember(networkInfo, selectedProfile) {
        selectedProfile.relayCandidates.firstOrNull()
            ?: if (networkInfo.localIp?.startsWith("192.168.2.") == true) "192.168.2.254" else "192.168.2.254"
    }
    val extenderSettingsEnabled = connectionStatus == "Connected to XIRO extender"

    val latestRemotePacket = remotePackets.firstOrNull()
    val betaUiState = BetaInference.buildUiState(
        host = host,
        networkInfo = networkInfo,
        telemetryResults = telemetryResults,
        watch3014Summary = watch3014Summary,
        recentRemotePackets = remotePackets,
        relayProbeResults = relayProbeResults,
        flightLogStatusText = hjLogStatusText
    )

    LaunchedEffect(Unit) {
        localLibraryManager.ensureFolders()
        localLibraryItems = localLibraryManager.scanLocalItems(cameraLibrary.items)
    }

    LaunchedEffect(networkInfo.localIp, networkInfo.gatewayIp) {
        val inferredProfile = detectConnectedProfile(networkInfo = networkInfo, host = host)
        if (selectedProfile.id != inferredProfile.id) {
            selectedProfile = inferredProfile
            liveLogs.add("${formatTimestamp(System.currentTimeMillis())}  Connected profile detected: ${inferredProfile.displayName}")
            if (liveLogs.size > 300) liveLogs.removeAt(0)
        }
    }

    fun appendLog(message: String) {
        liveLogs.add("${formatTimestamp(System.currentTimeMillis())}  $message")
        if (liveLogs.size > 300) liveLogs.removeAt(0)
    }

    fun isOnXiroWifi(): Boolean =
        networkInfo.localIp?.startsWith("192.168.2.") == true ||
            networkInfo.localIp?.startsWith("192.168.1.") == true

    LaunchedEffect(networkInfo.localIp, remoteUdpRunning, remoteUdpUserDisabled, remoteUdpProbeInProgress) {
        when {
            !isOnXiroWifi() && remoteUdpRunning -> {
                LiveFlightTelemetryHub.stop()
                appendLog("Live flight telemetry listener stopped: not on XIRO Wi-Fi")
            }

            isOnXiroWifi() && !remoteUdpUserDisabled && !remoteUdpProbeInProgress && !remoteUdpRunning -> {
                LiveFlightTelemetryHub.start(onLog = ::appendLog)
                appendLog("Live flight telemetry listener started")
            }
        }
    }

    fun startHjLogSession(tag: String): HjLogRecorderState {
        val state = hjLogRecorder.startSession(tag)
        hjLogStatusText = state.statusText
        appendLog("HJ log session started: ${state.activeFile?.absolutePath ?: state.statusText}")
        return state
    }

    fun stopHjLogSession(): HjLogRecorderState {
        val state = hjLogRecorder.stopSession()
        hjLogStatusText = state.statusText
        state.lastSavedFile?.let {
            appendLog("HJ log saved: ${it.absolutePath}")
        }
        return state
    }

    fun handleAutomaticStreamRecovery(reason: String) {
        val now = System.currentTimeMillis()
        if (now - lastAutoStreamReloadAtMs < 15_000L) return
        lastAutoStreamReloadAtMs = now
        scope.launch {
            val messageToken = ++autoRecoveryMessageToken
            val message = if (reason.contains("preemptive", ignoreCase = true)) {
                "Refreshing live feed before the camera RTSP session expires..."
            } else {
                "Live feed stalled. Reloading stream..."
            }
            captureRecoveryMessage = null
            appendLog("RTSP session watcher: $reason")
            playerReloadToken += 1
            delay(2_000)
            if (autoRecoveryMessageToken != messageToken) return@launch
            captureRecoveryMessage = message
            delay(1_500)
            if (captureRecoveryMessage == message && autoRecoveryMessageToken == messageToken) {
                captureRecoveryMessage = null
            }
        }
    }

    fun resolvedCommandUrl(command: XiroCommand): String =
        when (command.kind) {
            XiroCommandKind.UDP_6800_PROBE -> command.path
            XiroCommandKind.HTTP -> when {
                command.path.startsWith("http://") || command.path.startsWith("https://") -> command.path
                command.path.startsWith("/") -> "http://$host${command.path}"
                else -> "http://$host/${command.path}"
            }
        }

    fun setDebugMode(enabled: Boolean) {
        debugModeEnabled = enabled
        uiPrefs.edit().putBoolean("debug_mode_enabled", enabled).apply()
        if (!enabled && settingsPage == SettingsPage.DEBUG) {
            settingsPage = SettingsPage.ROOT
        }
        appendLog("Debug mode ${if (enabled) "enabled" else "disabled"}")
    }

    suspend fun performLibraryRefresh(reason: String) {
        libraryRefreshing = true
        val state = cameraMediaController.loadLibrary(host)
        try {
            cameraLibrary = state
            if (reason.contains("video", ignoreCase = true)) {
                localLibraryManager.createVideoPreviewPlaceholder("video_${System.currentTimeMillis()}")
            }
            localLibraryItems = localLibraryManager.scanLocalItems(state.items)
            cameraTraceLog.addAll(0, state.rawResponses.reversed())
            while (cameraTraceLog.size > 120) cameraTraceLog.removeAt(cameraTraceLog.lastIndex)
            lastLibraryRefreshAtMs = System.currentTimeMillis()
            appendLog("Library refresh ($reason): ${state.lastRefreshMessage}")
        } finally {
            libraryRefreshing = false
        }
    }

    LaunchedEffect(selectedProfile.id) {
        host = selectedProfile.primaryHost()
        cameraLibrary = CameraLibraryState(emptyList(), emptyList())
        lastCameraAction = null
        isRecording = false
        appendLog("Active profile set: ${selectedProfile.displayName}")
    }

    LaunchedEffect(selectedTab, host, selectedProfile.id) {
        if (selectedTab != BetaTab.LIBRARY) return@LaunchedEffect
        val now = System.currentTimeMillis()
        if (libraryRefreshing) return@LaunchedEffect
        if (now - lastLibraryRefreshAtMs < 2_500L) return@LaunchedEffect
        performLibraryRefresh("library tab opened")
    }

    LaunchedEffect(selectedTab, settingsPage, extenderSettingsEnabled, relayHost) {
        if (selectedTab == BetaTab.SETTINGS && extenderSettingsEnabled) {
            when (settingsPage) {
                SettingsPage.ROOT -> {
                    appendLog("Settings opened: auto requesting repeater status and bound camera")
                    relayProbeResults = relayProbe.probeSettingsRoot(relayHost)
                }
                SettingsPage.BIND_CAMERA -> {
                    appendLog("Bind extender screen opened: auto requesting repeater Wi-Fi list")
                    relayProbeResults = relayProbe.probeBindMenu(relayHost, forceRescan = true)
                }
                else -> Unit
            }
        }
    }

    LaunchedEffect(selectedTab, relayHost) {
        if (selectedTab != BetaTab.SETTINGS) {
            relayProbe.closeSession()
        }
    }

    LaunchedEffect(settingsPage) {
        if (settingsPage != SettingsPage.BIND_CAMERA) {
            pendingBindNetwork = null
            relayBindInProgress = false
        }
    }

    fun recordCameraOperation(op: CameraOperationResult) {
        lastCameraAction = op
        cameraTraceLog.addAll(0, op.entries.reversed())
        while (cameraTraceLog.size > 120) cameraTraceLog.removeAt(cameraTraceLog.lastIndex)
        appendLog("${op.title}: ${op.summary}")
    }

    fun downloadRemoteLibraryItem(
        item: CameraMediaItem,
        successMessagePrefix: String = "Downloaded remote camera file"
    ) {
        scope.launch {
            libraryDownloadProgress = LibraryDownloadProgress(title = item.name)
            localLibraryManager.downloadToHd(item) { bytesRead, totalBytes ->
                libraryDownloadProgress = LibraryDownloadProgress(
                    title = item.name,
                    bytesRead = bytesRead,
                    totalBytes = totalBytes
                )
            }.onSuccess {
                appendLog("$successMessagePrefix: ${it.name}")
                localLibraryItems = localLibraryManager.scanLocalItems(cameraLibrary.items)
            }.onFailure {
                appendLog("Remote download failed: ${it.message}")
            }
            delay(350)
            libraryDownloadProgress = null
        }
    }

    fun deleteLocalLibraryItem(item: LocalLibraryItem) {
        scope.launch {
            localLibraryManager.deleteLocalItem(item).onSuccess {
                appendLog("Deleted local item: ${item.name}")
                localLibraryItems = localLibraryManager.scanLocalItems(cameraLibrary.items)
                if (selectedLibraryPreview?.id == item.id) {
                    selectedLibraryPreview = null
                }
            }.onFailure {
                appendLog("Local delete failed: ${it.message}")
            }
        }
    }

    suspend fun waitForCaptureRecovery(
        phase: String,
        refreshLibraryReason: String? = null,
        reloadPlayerAfterRecovery: Boolean = showPlayer
    ) {
        appendLog("${phase}: waiting for camera host and Wi-Fi recovery")
        val recovery = cameraMediaController.waitForCameraRecovery(host)
        recordCameraOperation(recovery.operation)
        if (recovery.recovered) {
            if (refreshLibraryReason != null) {
                performLibraryRefresh(refreshLibraryReason)
            }
            if (reloadPlayerAfterRecovery && showPlayer) {
                playerReloadToken += 1
                appendLog("RTSP recovery reload after camera host returned")
            }
            captureRecoveryMessage = null
        } else {
            captureRecoveryMessage = "Camera Wi-Fi is still recovering. Reconnect to the camera when its network returns."
            appendLog("${phase}: recovery timed out before the camera host answered again")
        }
    }

    suspend fun showTransientCaptureMessage(message: String, durationMs: Long = 1500) {
        captureRecoveryMessage = message
        delay(durationMs)
        if (captureRecoveryMessage == message) {
            captureRecoveryMessage = null
        }
