                                                .padding(16.dp)
                                                .fillMaxWidth()
                                        ) {
                                            Text(
                                                text = "Version ${notes.version}",
                                                style = androidx.compose.material3.MaterialTheme.typography.headlineSmall,
                                                color = androidx.compose.material3.MaterialTheme.colorScheme.primary
                                            )
                                            Spacer(modifier = Modifier.height(16.dp))
                                            
                                            Text(
                                                text = "What's New",
                                                style = androidx.compose.material3.MaterialTheme.typography.titleMedium,
                                                color = androidx.compose.material3.MaterialTheme.colorScheme.secondary
                                            )
                                            notes.changes.forEach { change ->
                                                Text(
                                                    text = "- $change",
                                                    modifier = Modifier.padding(vertical = 4.dp),
                                                    style = androidx.compose.material3.MaterialTheme.typography.bodyMedium
                                                )
                                            }
                                            
                                            Spacer(modifier = Modifier.height(16.dp))
                                            
                                            Text(
                                                text = "Known Issues",
                                                style = androidx.compose.material3.MaterialTheme.typography.titleMedium,
                                                color = androidx.compose.material3.MaterialTheme.colorScheme.error
                                            )
                                            notes.knownIssues.forEach { issue ->
                                                Text(
                                                    text = "- $issue",
                                                    modifier = Modifier.padding(vertical = 4.dp),
                                                    style = androidx.compose.material3.MaterialTheme.typography.bodyMedium
                                                )
                                            }
                                        }
                                    }
                                }
                            }
                        }
                        BetaTab.LIBRARY -> {
                            item {
                                PullToRefreshLibraryCard(
                                    cameraLibrary = cameraLibrary,
                                    localItems = localLibraryItems,
                                    libraryViewMode = libraryViewMode,
                                    libraryRefreshing = libraryRefreshing,
                                    onSelectViewMode = { libraryViewMode = it },
                                    onOpenPreview = { item -> selectedLibraryPreview = item },
                                    onOpenRemotePreview = { item -> selectedRemoteLibraryPreview = item }
                                )
                            }
                        }

                    }
                }
            }
        }
    }
}
}


private fun cleanRelayField(raw: String): String {
    val trimmed = raw.trim()
    if (trimmed.isBlank() || trimmed == "--" || trimmed == "<empty body>") return "Unknown"
    if (trimmed.equals("ff", ignoreCase = true)) return "Unknown"
    if (trimmed.length <= 4 && trimmed.all { it.isDigit() || it.lowercaseChar() in 'a'..'f' }) return "Unknown"
    if (trimmed.startsWith("<?xml")) return "Connected, waiting for parsed camera info"
    if (trimmed.startsWith("failed to connect", ignoreCase = true)) return "Unavailable"
    if (trimmed.contains("connection refused", ignoreCase = true)) return "Unavailable"
    if (trimmed.contains("exception", ignoreCase = true)) return "Unavailable"
    if (trimmed.contains("SOCKET OK", ignoreCase = true)) return "Waiting for repeater response"
    return trimmed
}


private fun buildExportText(
    host: String,
    networkInfo: DroneNetworkInfo,
    portScanResults: List<PortScanResult>,
    targetedResults: List<TargetedProbeResult>,
    cameraInitResults: List<CameraInitResult>,
    telemetryResults: List<TelemetryResult>,
    telemetryDiffResults: List<TelemetryDiffResult>,
    watch3014Summary: Telemetry3014Summary?,
    watch3014Result: TelemetryResult?,
    remotePackets: List<RemoteTelemetryPacket>,
    results: List<CommandResult>,
    liveLogs: List<String>
): String {
    val portScanSnapshot = portScanResults.toList()
    val targetedSnapshot = targetedResults.toList()
    val cameraInitSnapshot = cameraInitResults.toList()
    val telemetrySnapshot = telemetryResults.toList()
    val telemetryDiffSnapshot = telemetryDiffResults.toList()
    val remotePacketsSnapshot = remotePackets.toList()
    val resultsSnapshot = results.toList()
    val liveLogsSnapshot = liveLogs.toList()

    val sb = StringBuilder()
    sb.appendLine("XIRO Lite Beta Export")
    sb.appendLine("========================================")
    sb.appendLine("Host: $host")
    sb.appendLine("Phone IP: ${networkInfo.localIp ?: "Unknown"}")
    sb.appendLine("Gateway: ${networkInfo.gatewayIp ?: "Unknown"}")
    sb.appendLine("Drone Guess: ${networkInfo.guessedDroneIp ?: "Unknown"}")
    sb.appendLine()

    fun section(name: String, content: () -> Unit) {
        sb.appendLine(name)
        sb.appendLine("----------------------------------------")
        content()
        sb.appendLine()
    }

    section("PORT SCAN RESULTS") {
        if (portScanSnapshot.isEmpty()) sb.appendLine("(none)")
        portScanSnapshot.forEach {
            sb.appendLine("${it.host}:${it.port}")
            sb.appendLine("Status: ${it.status}")
            sb.appendLine("Detail: ${it.detail}")
            sb.appendLine()
        }
    }
    section("TARGETED PROBE RESULTS") {
        if (targetedSnapshot.isEmpty()) sb.appendLine("(none)")
        targetedSnapshot.forEach {
            sb.appendLine(it.label)
            sb.appendLine("Endpoint: ${it.endpoint}")
            sb.appendLine("Status: ${it.status}")
            sb.appendLine(it.preview)
            sb.appendLine()
        }
    }
    section("CAMERA INIT RESULTS") {
        if (cameraInitSnapshot.isEmpty()) sb.appendLine("(none)")
        cameraInitSnapshot.forEach { sb.appendLine("${it.label}\n${it.url}\n${it.status}\n${it.preview}\n") }
    }
    section("TELEMETRY RESULTS") {
        if (telemetrySnapshot.isEmpty()) sb.appendLine("(none)")
        telemetrySnapshot.forEach { sb.appendLine("${it.label}\n${it.url}\n${it.status}\n${it.preview}\n") }
    }
    section("TELEMETRY DIFF RESULTS") {
        if (telemetryDiffSnapshot.isEmpty()) sb.appendLine("(none)")
        telemetryDiffSnapshot.forEach { sb.appendLine("${it.label}\n${it.url}\nBEFORE:\n${it.before}\nAFTER:\n${it.after}\n") }
    }
    section("3014 SUMMARY") {
        if (watch3014Summary == null) sb.appendLine("(none)") else {
            sb.appendLine("Motor / Arm Guess: ${watch3014Summary.motorStateGuess}")
            sb.appendLine("GPS Guess: ${watch3014Summary.gpsGuess}")
            sb.appendLine("Flight Mode Guess: ${watch3014Summary.flightModeGuess}")
            sb.appendLine("System Guess: ${watch3014Summary.systemStateGuess}")
            sb.appendLine("Aux Guess: ${watch3014Summary.auxStateGuess}")
            sb.appendLine("Camera Guess: ${watch3014Summary.cameraStateGuess}")
        }
    }
    section("WATCH 3014") {
        if (watch3014Result == null) sb.appendLine("(none)") else {
            sb.appendLine(watch3014Result.label)
            sb.appendLine(watch3014Result.url)
            sb.appendLine(watch3014Result.status)
            sb.appendLine(watch3014Result.preview)
        }
    }
    section("REMOTE UDP 6800") {
        if (remotePacketsSnapshot.isEmpty()) sb.appendLine("(none)")
        remotePacketsSnapshot.forEachIndexed { index, packet ->
            sb.appendLine("Packet ${index + 1}")
            sb.appendLine("Time: ${formatTimestamp(packet.timestampMs)}")
            sb.appendLine("Source: ${packet.sourceIp}:${packet.sourcePort}")
            sb.appendLine("Length: ${packet.length}")
            sb.appendLine("State: ${packet.stateGuess?.label ?: "Unknown"}")
            sb.appendLine("Control Triplet [19..21]: ${packet.controlTripletHex}")
            sb.appendLine("Phase Counter [79..80]: ${packet.phaseCounterHex}")
            sb.appendLine("Tail [86..88]: ${packet.tailHex}")
            sb.appendLine("Hex Preview: ${packet.hexPreview}")
            sb.appendLine()
        }
    }
    section("HTTP PROBE RESULTS") {
        if (resultsSnapshot.isEmpty()) sb.appendLine("(none)")
        resultsSnapshot.forEach { sb.appendLine("${it.label}\n${it.url}\n${it.status}\n${it.preview}\n") }
    }
    section("LIVE LOGS") {
        if (liveLogsSnapshot.isEmpty()) sb.appendLine("(none)") else liveLogsSnapshot.forEach { sb.appendLine(it) }
    }
    return sb.toString()
}

private fun buildCommandExperimentExportText(
    command: XiroCommand,
    resolvedUrl: String,
    host: String,
    networkInfo: DroneNetworkInfo,
    profile: LegacyDroneProfile,
    commandOperation: CameraOperationResult,
    recoveryOperation: CameraOperationResult,
    commandLogs: List<String>,
    startedAt: Long,
    finishedAt: Long
): String {
    val formatter = SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US)
    val durationSeconds = (finishedAt - startedAt) / 1000.0
    val sb = StringBuilder()

    fun section(name: String, content: () -> Unit) {
        sb.appendLine(name)
        sb.appendLine("----------------------------------------")
        content()
        sb.appendLine()
    }

    sb.appendLine("XIRO Lite Command Test Export")
    sb.appendLine("========================================")
    sb.appendLine("Command: ${command.name}")
    sb.appendLine("Path: ${command.path}")
    sb.appendLine("Resolved URL: $resolvedUrl")
    sb.appendLine("Description: ${command.notes.ifBlank { "No description provided." }}")
    sb.appendLine("Profile: ${profile.displayName}")
    sb.appendLine("Host: $host")
    sb.appendLine("Phone IP: ${networkInfo.localIp ?: "Unknown"}")
    sb.appendLine("Gateway: ${networkInfo.gatewayIp ?: "Unknown"}")
    sb.appendLine("Drone Guess: ${networkInfo.guessedDroneIp ?: "Unknown"}")
    sb.appendLine("Started: ${formatter.format(Date(startedAt))}")
    sb.appendLine("Finished: ${formatter.format(Date(finishedAt))}")
    sb.appendLine("Observed Window: ${String.format(Locale.US, "%.1f", durationSeconds)}s")
    sb.appendLine()

    section("COMMAND RESPONSE") {
        sb.appendLine("Title: ${commandOperation.title}")
        sb.appendLine("Summary: ${commandOperation.summary}")
        commandOperation.entries.forEachIndexed { index, entry ->
            sb.appendLine("${index + 1}. ${entry.action}")
            sb.appendLine("URL: ${entry.url}")
            sb.appendLine("Status: ${entry.status}")
            if (entry.body.isNotBlank()) sb.appendLine("Body: ${entry.body}")
            sb.appendLine()
        }
    }

    section("RECOVERY WATCH") {
        sb.appendLine("Title: ${recoveryOperation.title}")
        sb.appendLine("Summary: ${recoveryOperation.summary}")
        recoveryOperation.entries.forEachIndexed { index, entry ->
            sb.appendLine("${index + 1}. ${entry.action}")
            sb.appendLine("URL: ${entry.url}")
            sb.appendLine("Status: ${entry.status}")
            if (entry.body.isNotBlank()) sb.appendLine("Body: ${entry.body}")
            sb.appendLine()
        }
    }

    section("APP LOG WINDOW") {
        if (commandLogs.isEmpty()) {
            sb.appendLine("(none)")
        } else {
            commandLogs.forEach(sb::appendLine)
        }
    }

    return sb.toString()
}

private fun buildUdpProbeExperimentExportText(
    command: XiroCommand,
    host: String,
    networkInfo: DroneNetworkInfo,
    profile: LegacyDroneProfile,
    watch3014Summary: Telemetry3014Summary?,
    packets: List<RemoteTelemetryPacket>,
    commandLogs: List<String>,
    startedAt: Long,
    finishedAt: Long,
    hjLogFile: File? = null
): String {
    val formatter = SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US)
    val durationSeconds = (finishedAt - startedAt) / 1000.0
    val packetSnapshot = packets.toList()
    val latestPacket = packetSnapshot.lastOrNull()
    val sb = StringBuilder()

    fun section(name: String, content: () -> Unit) {
        sb.appendLine(name)
        sb.appendLine("----------------------------------------")
        content()
        sb.appendLine()
    }

    sb.appendLine("XIRO Lite UDP Probe Export")
    sb.appendLine("========================================")
    sb.appendLine("Command: ${command.name}")
    sb.appendLine("Path: ${command.path}")
    sb.appendLine("Description: ${command.notes.ifBlank { "No description provided." }}")
    sb.appendLine("Profile: ${profile.displayName}")
    sb.appendLine("Host: $host")
    sb.appendLine("Phone IP: ${networkInfo.localIp ?: "Unknown"}")
    sb.appendLine("Gateway: ${networkInfo.gatewayIp ?: "Unknown"}")
    sb.appendLine("Drone Guess: ${networkInfo.guessedDroneIp ?: "Unknown"}")
    sb.appendLine("Started: ${formatter.format(Date(startedAt))}")
    sb.appendLine("Finished: ${formatter.format(Date(finishedAt))}")
    sb.appendLine("Observed Window: ${String.format(Locale.US, "%.1f", durationSeconds)}s")
    sb.appendLine("HJ Log: ${hjLogFile?.absolutePath ?: "Not saved"}")
    sb.appendLine()

    section("UDP CAPTURE SUMMARY") {
        sb.appendLine("Packets Captured: ${packetSnapshot.size}")
        if (packetSnapshot.isEmpty()) {
            sb.appendLine("No UDP 6800 packets were captured in the 20 second window.")
        } else {
            val sourceCounts = packetSnapshot.groupingBy { "${it.sourceIp}:${it.sourcePort}" }.eachCount()
            sb.appendLine("Unique Sources: ${sourceCounts.size}")
            sourceCounts.forEach { (source, count) ->
                sb.appendLine("$source -> $count packets")
            }
            sb.appendLine("First Packet: ${formatTimestamp(packetSnapshot.first().timestampMs)}")
            sb.appendLine("Last Packet: ${formatTimestamp(packetSnapshot.last().timestampMs)}")
            sb.appendLine("Latest State Guess: ${latestPacket?.stateGuess?.label ?: "Unknown"}")
            sb.appendLine("Latest Control Triplet [19..21]: ${latestPacket?.controlTripletHex ?: "(n/a)"}")
            sb.appendLine("Latest Phase Counter [79..80]: ${latestPacket?.phaseCounterHex ?: "(n/a)"}")
            sb.appendLine("Latest Tail [86..88]: ${latestPacket?.tailHex ?: "(n/a)"}")
        }
    }

    section("LEGACY TELEMETRY MODEL TARGETS") {
        LegacyTelemetryHints.buildRecoveredTargets(
            watch3014Summary = watch3014Summary,
            latestRemotePacket = latestPacket
        ).forEach { target ->
            sb.appendLine("${target.fieldName} [${target.confidence}]")
            sb.appendLine(target.description)
            target.currentLeads.forEach { lead ->
                sb.appendLine("Lead: $lead")
            }
            sb.appendLine()
        }
        sb.appendLine("Legacy positioning enum: GPS=1, OpticalFlow=2, Attitude=3")
        sb.appendLine("Legacy remote battery path: getRemoteElectricity(...) callback")
    }

    section("LATEST 3014 SUMMARY") {
        if (watch3014Summary == null) {
            sb.appendLine("(none)")
        } else {
            sb.appendLine("3014/2005 = ${watch3014Summary.value(2005) ?: "--"}")
            sb.appendLine("3014/2033 = ${watch3014Summary.value(2033) ?: "--"}")
            sb.appendLine("3014/2034 = ${watch3014Summary.value(2034) ?: "--"}")
            sb.appendLine("3014/2010 = ${watch3014Summary.value(2010) ?: "--"}")
            sb.appendLine("3014/2011 = ${watch3014Summary.value(2011) ?: "--"}")
            sb.appendLine("3014/3009 = ${watch3014Summary.value(3009) ?: "--"}")
            sb.appendLine("Motor Guess: ${watch3014Summary.motorStateGuess}")
            sb.appendLine("GPS Guess: ${watch3014Summary.gpsGuess}")
            sb.appendLine("Flight Mode Guess: ${watch3014Summary.flightModeGuess}")
            sb.appendLine("System Guess: ${watch3014Summary.systemStateGuess}")
            sb.appendLine("Aux Guess: ${watch3014Summary.auxStateGuess}")
            sb.appendLine("Camera Guess: ${watch3014Summary.cameraStateGuess}")
        }
    }

    section("STATE GUESS COUNTS") {
        val stateCounts = packetSnapshot
            .map { it.stateGuess?.label ?: "Unknown" }
            .groupingBy { it }
            .eachCount()
        if (stateCounts.isEmpty()) {
            sb.appendLine("(none)")
        } else {
            stateCounts.forEach { (label, count) ->
                sb.appendLine("$label -> $count")
            }
        }
    }

    section("WATCHED OFFSETS (LAST PACKET)") {
        if (latestPacket == null) {
            sb.appendLine("(none)")
        } else {
            latestPacket.watchedOffsets.forEach { watched ->
                val hint = LegacyTelemetryHints.offsetHint(watched.index)
                sb.appendLine(
                    "UDP[${watched.index}] = ${watched.unsigned} (${watched.hex})" +
                        (if (watched.changed) " changed" else "") +
                        (hint?.let { " :: $it" } ?: "")
                )
            }
        }
    }

    section("WATCHED PAIRS (LAST PACKET)") {
        if (latestPacket == null) {
            sb.appendLine("(none)")
        } else {
            latestPacket.watchedPairs.forEach { pair ->
                val hint = LegacyTelemetryHints.pairHint(pair.startIndex)
                sb.appendLine(
                    "UDP[${pair.startIndex}..${pair.startIndex + 1}] = ${pair.u16le} (s16=${pair.s16le}, hex=${pair.hex})" +
                        (hint?.let { " :: $it" } ?: "")
                )
            }
        }
    }

    section("CALIBRATION CHECKLIST") {
        LegacyTelemetryHints.calibrationChecklist().forEach(sb::appendLine)
    }

    section("UDP PACKET WINDOW") {
        if (packetSnapshot.isEmpty()) {
            sb.appendLine("(none)")
        } else {
            packetSnapshot.forEachIndexed { index, packet ->
                sb.appendLine("Packet ${index + 1}")
                sb.appendLine("Time: ${formatTimestamp(packet.timestampMs)}")
                sb.appendLine("Source: ${packet.sourceIp}:${packet.sourcePort}")
                sb.appendLine("Length: ${packet.length}")
                sb.appendLine("State: ${packet.stateGuess?.label ?: "Unknown"}")
                sb.appendLine("Control Triplet [19..21]: ${packet.controlTripletHex}")
                sb.appendLine("Phase Counter [79..80]: ${packet.phaseCounterHex}")
                sb.appendLine("Tail [86..88]: ${packet.tailHex}")
                sb.appendLine("Hex Preview: ${packet.hexPreview}")
                sb.appendLine()
            }
        }
    }

    section("APP LOG WINDOW") {
        if (commandLogs.isEmpty()) {
            sb.appendLine("(none)")
        } else {
            commandLogs.forEach(sb::appendLine)
        }
    }

    return sb.toString()
}

