@Composable
private fun PreflightWarningRow(warning: FlightWarning) {
    val containerColor = when (warning.severity) {
        FlightWarningSeverity.INFO -> Color(0xAA274152)
        FlightWarningSeverity.CAUTION -> Color(0xAA5C4300)
        FlightWarningSeverity.CRITICAL -> Color(0xAA5C1F1F)
    }
    val indicatorColor = when (warning.severity) {
        FlightWarningSeverity.INFO -> Color(0xFF64B5F6)
        FlightWarningSeverity.CAUTION -> Color(0xFFFFC107)
        FlightWarningSeverity.CRITICAL -> Color(0xFFFF6E6E)
    }

    Card(
        colors = CardDefaults.cardColors(containerColor = containerColor)
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 12.dp, vertical = 10.dp),
            horizontalArrangement = Arrangement.spacedBy(10.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Box(
                modifier = Modifier
                    .size(10.dp)
                    .clip(CircleShape)
                    .background(indicatorColor)
            )
            Column(verticalArrangement = Arrangement.spacedBy(2.dp)) {
                Text(warning.title, color = Color.White)
                Text(warning.detail, color = Color(0xFFD7DCE3), style = MaterialTheme.typography.bodySmall)
            }
        }
    }
}



