            shape = CircleShape,
            colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF6BD224), contentColor = Color.Black)
        ) {
            Icon(
                imageVector = Icons.Outlined.CameraAlt,
                contentDescription = "Open Camera",
                modifier = Modifier.size(52.dp)
            )
        }
        Text(
            text = detectedDroneLabel,
            modifier = Modifier
                .align(Alignment.Center)
                .padding(top = 184.dp),
            color = Color(0xFFB7BDC8),
            style = MaterialTheme.typography.titleSmall
        )
    }
}

private fun cameraHomeDroneLabel(profile: LegacyDroneProfile): String =
    when (profile.id) {
        "xplorer" -> "XPLORER"
        "xplorer_4k" -> "XPLORER 4K"
        "gimbal_handheld" -> "GIMBAL HANDHELD"
        "repeater_tiny_q" -> "TINY-Q RELAY"
        else -> profile.displayName.uppercase(Locale.US)
    }

private suspend fun detectConnectedProfile(
    networkInfo: DroneNetworkInfo,
    host: String
): LegacyDroneProfile {
    val localIp = networkInfo.localIp.orEmpty()
    val gatewayIp = networkInfo.gatewayIp.orEmpty()

    if (localIp.startsWith("192.168.1.") || gatewayIp.startsWith("192.168.1.")) {
        return LegacyCompatibilityCatalog.gimbalHandheld
    }

    if (localIp.startsWith("192.168.2.") || gatewayIp.startsWith("192.168.2.")) {
        val cameraHost = host.trim().takeIf { it.isNotBlank() && !it.startsWith("192.168.2.") }
            ?: LegacyCompatibilityCatalog.xplorer.primaryHost()
        return if (probeAmbarella4k(cameraHost)) {
            LegacyCompatibilityCatalog.xplorer4k
        } else {
            LegacyCompatibilityCatalog.xplorer
        }
    }

    return LegacyCompatibilityCatalog.defaultProfile
}

private suspend fun probeAmbarella4k(host: String): Boolean = withContext(Dispatchers.IO) {
    val urlString = "http://$host/cgi-bin/get_amba_4k_version"
    try {
        val conn = URL(urlString).openConnection() as HttpURLConnection
        conn.requestMethod = "GET"
        conn.connectTimeout = 1500
        conn.readTimeout = 1500
        conn.setRequestProperty("User-Agent", "XIRO-Lite")
        conn.setRequestProperty("Connection", "close")

        val code = conn.responseCode
        val body = try {
            val stream = if (code in 200..299) conn.inputStream else conn.errorStream
            if (stream != null) {
                BufferedReader(InputStreamReader(stream)).use { it.readText() }
            } else {
                ""
            }
        } catch (_: Exception) {
            ""
        }

        code in 200..299 && (
            body.contains("amba", ignoreCase = true) ||
                body.contains("4k", ignoreCase = true) ||
                body.contains("version", ignoreCase = true) ||
                body.isBlank()
            )
    } catch (_: Exception) {
        false
    }
}


@Composable
private fun CameraStepSequenceCard(lastAction: CameraOperationResult?) {
    XiroAppCard {
        Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
            Text("Capture Prep Sequence", style = MaterialTheme.typography.titleLarge, color = Color(0xFFF2F4F7))
            Text("Shows each camera step explicitly so you can see where photo/video preparation fails.", color = Color(0xFFD7DCE3))
            if (lastAction == null) {
                Text("No capture sequence logged yet.", color = Color(0xFFD7DCE3))
            } else {
                Text("Action: ${lastAction.title}", color = Color(0xFFF2F4F7))
                lastAction.entries.forEachIndexed { index, entry ->
                    Card(
                        modifier = Modifier.fillMaxWidth(),
                        colors = CardDefaults.cardColors(containerColor = Color(0xFF2D333D))
                    ) {
                        Column(Modifier.padding(10.dp), verticalArrangement = Arrangement.spacedBy(4.dp)) {
                            Text("${index + 1}. ${entry.action}", color = Color(0xFFF2F4F7))
                            Text(entry.status, style = MaterialTheme.typography.bodySmall, color = Color(0xFFD7DCE3))
                            if (entry.url.isNotBlank()) Text(entry.url, style = MaterialTheme.typography.bodySmall, fontFamily = FontFamily.Monospace, color = Color(0xFFD7DCE3))
                            if (entry.body.isNotBlank()) Text(entry.body.take(180), style = MaterialTheme.typography.bodySmall, fontFamily = FontFamily.Monospace, color = Color(0xFFD7DCE3))
                        }
                    }
                }
            }
        }
    }
}


@Composable
@OptIn(ExperimentalLayoutApi::class)
private fun FpvActionRow(
    showPlayer: Boolean,
    showHud: Boolean,
    captureMode: CaptureMode,
    isRecording: Boolean,
    onToggleHud: () -> Unit,
    onToggleMode: () -> Unit,
    onPrimaryCapture: () -> Unit,
    onOpenLibrary: () -> Unit,
    onTogglePlayer: () -> Unit,
    onFullScreen: () -> Unit,
    onProbeRelay: () -> Unit,
    onExport: () -> Unit
) {
    Card(modifier = Modifier.fillMaxWidth()) {
        FlowRow(
            modifier = Modifier.padding(12.dp),
            horizontalArrangement = Arrangement.spacedBy(8.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            Button(onClick = onTogglePlayer) { Text(if (showPlayer) "Hide Player" else "Show Player") }
            Button(onClick = onFullScreen, enabled = showPlayer) { Text("Full Screen") }
            Button(onClick = onToggleHud) { Text(if (showHud) "Hide HUD" else "Show HUD") }
            Button(onClick = onToggleMode) { Text(if (captureMode == CaptureMode.PHOTO) "Mode: Photo" else "Mode: Video") }
            Button(onClick = onPrimaryCapture) { Text(primaryCaptureLabel(captureMode, isRecording)) }
            Button(onClick = onOpenLibrary) { Text("Library") }
            Button(onClick = onProbeRelay) { Text("Probe Relay") }
            Button(onClick = onExport) { Text("Export") }
        }
    }
}


private fun primaryCaptureLabel(captureMode: CaptureMode, isRecording: Boolean): String =
    when (captureMode) {
        CaptureMode.PHOTO -> "Take Photo"
        CaptureMode.VIDEO -> if (isRecording) "Stop Video" else "Start Video"
    }

@Composable
private fun PlayerCard(
    rtspUrl: String,
    playerReloadToken: Int,
    captureRecoveryMessage: String?,
    captureMode: CaptureMode,
    isRecording: Boolean,
    showHud: Boolean,
    onToggleHud: () -> Unit,
    onToggleMode: () -> Unit,
    onPrimaryCapture: () -> Unit,
    onOpenLibrary: () -> Unit,
    onFullScreen: () -> Unit,
    onRecoveryRequested: (String) -> Unit = {},
    onLog: (String) -> Unit
) {
    Card(modifier = Modifier.fillMaxWidth()) {
        Column(Modifier.padding(12.dp)) {
            Text("FPV Stream", style = MaterialTheme.typography.titleMedium)
            Text(rtspUrl)
            Spacer(modifier = Modifier.height(8.dp))
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(360.dp)
                    .background(Color.Black)
            ) {
                RtspPlayer(
                    url = rtspUrl,
                    reloadToken = playerReloadToken,
                    modifier = Modifier.fillMaxSize(),
                    onRecoveryRequested = onRecoveryRequested,
                    onLog = onLog
                )
                Column(
                    modifier = Modifier
                        .align(Alignment.TopStart)
                        .fillMaxWidth()
                        .padding(12.dp)
                ) {
                    Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                        Button(onClick = onFullScreen) { Text("Full Screen") }
                        Button(onClick = onToggleHud) { Text(if (showHud) "Hide HUD" else "Show HUD") }
                    }
                }
                captureRecoveryMessage?.let { msg ->
                    Card(
                        modifier = Modifier
                            .align(Alignment.Center)
                            .padding(20.dp),
                        shape = RoundedCornerShape(20.dp)
                    ) {
                        Column(Modifier.padding(horizontal = 20.dp, vertical = 16.dp), horizontalAlignment = Alignment.CenterHorizontally) {
                            Text("Reconnecting Camera", style = MaterialTheme.typography.headlineLarge)
                            Spacer(modifier = Modifier.height(6.dp))
                            Text(msg)
                        }
                    }
                }
                Row(
                    modifier = Modifier
                        .align(Alignment.BottomCenter)
                        .fillMaxWidth()
                        .padding(16.dp),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Button(onClick = onOpenLibrary) { Text("Library") }
                    Button(onClick = onToggleMode) {
                        Text(if (captureMode == CaptureMode.PHOTO) "Photo" else "Video")
                    }
                    Button(
                        onClick = onPrimaryCapture,
                        modifier = Modifier
                            .size(84.dp)
                            .clip(CircleShape),
                        colors = if (captureMode == CaptureMode.VIDEO && isRecording) ButtonDefaults.buttonColors(containerColor = Color.Red) else ButtonDefaults.buttonColors()
                    ) {
                        Text(
                            when (captureMode) {
                                CaptureMode.PHOTO -> "Snap"
                                CaptureMode.VIDEO -> if (isRecording) "Stop" else "Rec"
                            }
                        )
                    }
                }
            }
        }
    }
}


