private fun isSelectableBindSsid(raw: String): Boolean {
    val trimmed = raw.trim()
    if (trimmed.isBlank()) return false
    if (trimmed == "<empty body>") return false
    if (trimmed.startsWith("<") || trimmed.startsWith("{") || trimmed.startsWith("[")) return false
    if (trimmed.contains("connection refused", ignoreCase = true)) return false
    if (trimmed.contains("exception", ignoreCase = true)) return false
    if (trimmed.contains("timeout", ignoreCase = true)) return false
    if (trimmed.contains("socket ok", ignoreCase = true)) return false
    if (trimmed.contains("bad request", ignoreCase = true)) return false
    return trimmed.any { it.isLetterOrDigit() } && trimmed.length in 1..64
}

private fun defaultRelayBindPasswordForCandidate(candidate: RelayWifiCandidate): String? {
    val ssid = candidate.ssid.trim()
    return when {
        ssid.startsWith("UG3300EN_", ignoreCase = true) -> "4008073888"
        ssid.startsWith("UG3300-", ignoreCase = true) -> "4008073888"
        else -> null
    }
}


