@Composable
private fun CameraCaptureCard(lastAction: CameraOperationResult?) {
    XiroAppCard {
        Column(Modifier.padding(16.dp), verticalArrangement = Arrangement.spacedBy(10.dp)) {
            Text("Camera Capture", style = MaterialTheme.typography.titleLarge, color = Color(0xFFF2F4F7))
            Text(
                "Uses the observed XIRO camera flow: 3005 date sync, 3006 time sync, 2016 prep, 3001 mode switch, then 1001 photo or 2001 par=1/0 video with 3015 library refresh.",
                color = Color(0xFFD7DCE3)
            )
            if (lastAction == null) {
                Text("No camera action sent yet.", color = Color(0xFFD7DCE3))
            } else {
                Text("Last action: ${lastAction.title}", color = Color(0xFFF2F4F7))
                Text("Summary: ${lastAction.summary}", color = Color(0xFFD7DCE3))
