            TextButton(onClick = onDismiss) { Text("OK") }
        }
    )
}


private fun loadBitmapFromUrl(url: String): android.graphics.Bitmap? {
    return try {
        val request = okhttp3.Request.Builder().url(url).header("User-Agent", "XIRO-Lite-Beta").build()
        okhttp3.OkHttpClient.Builder()
            .connectTimeout(2, java.util.concurrent.TimeUnit.SECONDS)
            .readTimeout(3, java.util.concurrent.TimeUnit.SECONDS)
            .build()
            .newCall(request)
            .execute().use { response ->
                val bytes = response.body?.bytes() ?: return null
                android.graphics.BitmapFactory.decodeByteArray(bytes, 0, bytes.size)
            }
    } catch (_: Exception) {
        null
    }
}

private fun loadLocalPreviewBitmap(item: LocalLibraryItem): android.graphics.Bitmap? {
    val file = item.hdFile ?: item.previewFile ?: return null
    if (!file.exists()) return null
    return try {
        if (item.kind == MediaKind.PHOTO) {
            BitmapFactory.decodeFile(file.absolutePath)
        } else {
            val retriever = MediaMetadataRetriever()
            try {
                retriever.setDataSource(file.absolutePath)
                retriever.frameAtTime
            } finally {
                retriever.release()
            }
        }
    } catch (_: Exception) {
        null
    }
}

private fun buildLocalLibraryMediaInfo(item: LocalLibraryItem): LibraryMediaInfo {
    val file = item.hdFile ?: item.previewFile
    if (file == null || !file.exists()) {
        return LibraryMediaInfo(
            fileName = item.name,
            sizeText = "Unknown",
            resolutionText = "Unknown",
            capturedText = "Unknown",
            durationText = if (item.kind == MediaKind.VIDEO) "Unknown" else null
        )
    }
    val capturedText = file.lastModified().takeIf { it > 0L }?.let(::formatLibraryTimestamp) ?: "Unknown"
    return if (item.kind == MediaKind.PHOTO) {
        val bounds = decodeImageBounds(file)
        LibraryMediaInfo(
            fileName = file.name,
            sizeText = humanReadableBytes(file.length()),
            resolutionText = bounds?.let { "${it.first} x ${it.second}" } ?: "Unknown",
            capturedText = capturedText
        )
    } else {
        val metadata = readVideoMetadata(file.absolutePath, null)
        LibraryMediaInfo(
            fileName = file.name,
            sizeText = humanReadableBytes(file.length()),
            resolutionText = metadata.first?.let { size ->
                size.first?.let { width ->
                    size.second?.let { height -> "$width x $height" }
                }
            } ?: "Unknown",
            capturedText = capturedText,
            durationText = metadata.second?.let(::formatDurationMillis) ?: "Unknown"
        )
    }
}

private fun buildRemoteLibraryMediaInfo(item: CameraMediaItem): LibraryMediaInfo {
    val headerInfo = readRemoteFileHeaders(item.downloadUrl)
    val capturedText = headerInfo.second?.let(::formatLibraryTimestamp) ?: "Unknown"
    return if (item.kind == MediaKind.PHOTO) {
        val bounds = decodeRemoteImageBounds(item.previewUrl ?: item.downloadUrl)
        LibraryMediaInfo(
            fileName = item.name,
            sizeText = humanReadableBytes(headerInfo.first),
            resolutionText = bounds?.let { "${it.first} x ${it.second}" } ?: "Unknown",
            capturedText = capturedText
        )
    } else {
        val metadata = readVideoMetadata(item.downloadUrl, mapOf("User-Agent" to "XIRO-Lite-Beta"))
        val resolutionText = metadata.first?.let { size ->
            size.first?.let { width ->
                size.second?.let { height -> "$width x $height" }
            }
        } ?: "Unknown"
        LibraryMediaInfo(
            fileName = item.name,
            sizeText = humanReadableBytes(headerInfo.first),
            resolutionText = resolutionText,
            capturedText = capturedText,
            durationText = metadata.second?.let(::formatDurationMillis) ?: "Unknown"
        )
    }
}

private fun readRemoteFileHeaders(url: String): Pair<Long?, Long?> {
    return try {
        val connection = (URL(url).openConnection() as HttpURLConnection).apply {
            requestMethod = "GET"
            connectTimeout = 2_500
            readTimeout = 2_500
            setRequestProperty("User-Agent", "XIRO-Lite-Beta")
            instanceFollowRedirects = true
        }
        try {
            connection.connect()
            val size = connection.contentLengthLong.takeIf { it > 0L }
            val lastModified = connection.lastModified.takeIf { it > 0L }
            connection.inputStream?.close()
            size to lastModified
        } finally {
            connection.disconnect()
        }
    } catch (_: Exception) {
        null to null
    }
}

private fun decodeImageBounds(file: File): Pair<Int, Int>? {
    return try {
        val options = BitmapFactory.Options().apply { inJustDecodeBounds = true }
        BitmapFactory.decodeFile(file.absolutePath, options)
        if (options.outWidth > 0 && options.outHeight > 0) {
            options.outWidth to options.outHeight
        } else {
            null
        }
    } catch (_: Exception) {
        null
    }
}

private fun decodeRemoteImageBounds(url: String): Pair<Int, Int>? {
    return try {
        val connection = (URL(url).openConnection() as HttpURLConnection).apply {
            connectTimeout = 2_500
            readTimeout = 3_000
            setRequestProperty("User-Agent", "XIRO-Lite-Beta")
            instanceFollowRedirects = true
        }
        try {
            connection.connect()
            connection.inputStream.use { input ->
                val options = BitmapFactory.Options().apply { inJustDecodeBounds = true }
                BitmapFactory.decodeStream(input, null, options)
                if (options.outWidth > 0 && options.outHeight > 0) {
                    options.outWidth to options.outHeight
                } else {
                    null
                }
            }
        } finally {
            connection.disconnect()
        }
    } catch (_: Exception) {
        null
    }
}

private fun readVideoMetadata(
    source: String,
    headers: Map<String, String>?
): Pair<Pair<Int?, Int?>?, Long?> {
    return try {
        val retriever = MediaMetadataRetriever()
        try {
            if (headers == null) {
                retriever.setDataSource(source)
            } else {
                retriever.setDataSource(source, headers)
            }
            val width = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_VIDEO_WIDTH)?.toIntOrNull()
            val height = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_VIDEO_HEIGHT)?.toIntOrNull()
            val durationMs = retriever.extractMetadata(MediaMetadataRetriever.METADATA_KEY_DURATION)?.toLongOrNull()
            (width to height) to durationMs
        } finally {
            retriever.release()
        }
    } catch (_: Exception) {
        null to null
    }
}

private fun humanReadableBytes(size: Long?): String {
    if (size == null || size < 0L) return "Unknown"
    if (size < 1024L) return "$size B"
    val kb = size / 1024.0
    if (kb < 1024.0) return String.format(Locale.US, "%.1f KB", kb)
    val mb = kb / 1024.0
    if (mb < 1024.0) return String.format(Locale.US, "%.1f MB", mb)
    val gb = mb / 1024.0
    return String.format(Locale.US, "%.2f GB", gb)
}

private fun formatLibraryTimestamp(timestampMs: Long): String {
    return SimpleDateFormat("yyyy-MM-dd HH:mm:ss", Locale.US).format(Date(timestampMs))
}

private fun formatDurationMillis(durationMs: Long): String {
    val totalSeconds = durationMs / 1000L
    val hours = totalSeconds / 3600L
    val minutes = (totalSeconds % 3600L) / 60L
    val seconds = totalSeconds % 60L
    return if (hours > 0) {
        String.format(Locale.US, "%d:%02d:%02d", hours, minutes, seconds)
    } else {
        String.format(Locale.US, "%d:%02d", minutes, seconds)
    }
}


